// MARK: - AES Encryption Engine

final class AESEncryptionEngine {
    
    static let keySize = kCCKeySizeAES256
    static let blockSize = kCCBlockSizeAES128
    static let ivSize = kCCBlockSizeAES128
    
    /// Generates a cryptographically secure random key
    static func generateKey() throws -> Data {
        var keyData = Data(count: keySize)
        let result = keyData.withUnsafeMutableBytes { buffer in
            SecRandomCopyBytes(kSecRandomDefault, keySize, buffer.baseAddress!)
        }
        
        guard result == errSecSuccess else {
            throw DataSecurityError.keyGenerationFailed
        }
        
        return keyData
    }
    
    /// Generates a cryptographically secure random IV
    static func generateIV() throws -> Data {
        var ivData = Data(count: ivSize)
        let result = ivData.withUnsafeMutableBytes { buffer in
            SecRandomCopyBytes(kSecRandomDefault, ivSize, buffer.baseAddress!)
        }
        
        guard result == errSecSuccess else {
            throw DataSecurityError.keyGenerationFailed
        }
        
        return ivData
    }
    
    /// Encrypts data using AES-256-CBC with PKCS7 padding
    /// Returns: IV (16 bytes) + ciphertext
    static func encrypt(data: Data, key: Data) throws -> Data {
        let iv = try generateIV()
        
        let bufferSize = data.count + blockSize
        var encryptedData = Data(count: bufferSize)
        var encryptedLength: Int = 0
        
        let status = key.withUnsafeBytes { keyBytes in
            iv.withUnsafeBytes { ivBytes in
                data.withUnsafeBytes { dataBytes in
                    encryptedData.withUnsafeMutableBytes { encryptedBytes in
                        CCCrypt(
                            CCOperation(kCCEncrypt),
                            CCAlgorithm(kCCAlgorithmAES),
                            CCOptions(kCCOptionPKCS7Padding),
                            keyBytes.baseAddress,
                            keySize,
                            ivBytes.baseAddress,
                            dataBytes.baseAddress,
                            data.count,
                            encryptedBytes.baseAddress,
                            bufferSize,
                            &encryptedLength
                        )
                    }
                }
            }
        }
        
        guard status == kCCSuccess else {
            throw DataSecurityError.encryptionFailed(status: status)
        }
        
        encryptedData.count = encryptedLength
        
        // Prepend IV to ciphertext
        var result = iv
        result.append(encryptedData)
        return result
    }
    
    /// Decrypts data that was encrypted with the encrypt function
    /// Expects: IV (16 bytes) + ciphertext
    static func decrypt(data: Data, key: Data) throws -> Data {
        guard data.count > ivSize else {
            throw DataSecurityError.invalidData
        }
        
        let iv = data.prefix(ivSize)
        let ciphertext = data.suffix(from: ivSize)
        
        let bufferSize = ciphertext.count + blockSize
        var decryptedData = Data(count: bufferSize)
        var decryptedLength: Int = 0
        
        let status = key.withUnsafeBytes { keyBytes in
            iv.withUnsafeBytes { ivBytes in
                ciphertext.withUnsafeBytes { cipherBytes in
                    decryptedData.withUnsafeMutableBytes { decryptedBytes in
                        CCCrypt(
                            CCOperation(kCCDecrypt),
                            CCAlgorithm(kCCAlgorithmAES),
                            CCOptions(kCCOptionPKCS7Padding),
                            keyBytes.baseAddress,
                            keySize,
                            ivBytes.baseAddress,
                            cipherBytes.baseAddress,
                            ciphertext.count,
                            decryptedBytes.baseAddress,
                            bufferSize,
                            &decryptedLength
                        )
                    }
                }
            }
        }
        
        guard status == kCCSuccess else {
            throw DataSecurityError.decryptionFailed(status: status)
        }
        
        decryptedData.count = decryptedLength
        return decryptedData
    }
}

