final class DataSecurityManager {
    
    static let shared = DataSecurityManager()
    
    private let keychainManager = KeychainManager.shared
    private let encoder = JSONEncoder()
    private let decoder = JSONDecoder()
    
    private let credentialsAccount = "com.app.encrypted.credentials"
    private let paymentTokenAccount = "com.app.encrypted.paymentToken"
    private let personalInfoAccount = "com.app.encrypted.personalInfo"
    
    private var cachedKey: Data?
    private let keyAccessQueue = DispatchQueue(label: "com.app.datasecurity.keyqueue", attributes: .concurrent)
    
    private init() {
        encoder.dateEncodingStrategy = .iso8601
        decoder.dateDecodingStrategy = .iso8601
    }
    
    // MARK: - Key Management (Stored securely in Keychain, NOT hardcoded)
    
    /// Retrieves or generates the encryption key, stored securely in the iOS Keychain
    private func getEncryptionKey() throws -> Data {
        // Check cache first (thread-safe read)
        if let key = keyAccessQueue.sync(execute: { cachedKey }) {
            return key
        }
        
        do {
            let key = try keychainManager.retrieveKey()
            keyAccessQueue.async(flags: .barrier) { [weak self] in
                self?.cachedKey = key
            }
            return key
        } catch {
            // Key doesn't exist yet — generate and store a new one
            let newKey = try AESEncryptionEngine.generateKey()
            try keychainManager.saveKey(newKey)
            keyAccessQueue.async(flags: .barrier) { [weak self] in
                self?.cachedKey = newKey
            }
            return newKey
        }
    }
    
    /// Rotates the encryption key. Call this periodically or on security events.
    /// WARNING: All previously encrypted data must be re-encrypted with the new key.
    func rotateEncryptionKey() throws {
        // Retrieve all existing data with old key
        let credentials = try? retrieveCredentials()
        let paymentToken = try? retrievePaymentToken()
        let personalInfo = try? retrievePersonalInfo()
        
        // Generate and store new key
        let newKey = try AESEncryptionEngine.generateKey()
        try keychainManager.saveKey(newKey)
        keyAccessQueue.async(flags: .barrier) { [weak self] in
            self?.cachedKey = newKey
        }
        
        // Re-encrypt all existing data with new key
        if let credentials = credentials {
            try storeCredentials(credentials)
        }
        if let paymentToken = paymentToken {
            try storePaymentToken(paymentToken)
        }
        if let personalInfo = personalInfo {
            try storePersonalInfo(personalInfo)
        }
    }
    
    // MARK: - Generic Encrypt/Decrypt
    
    func encrypt<T: Encodable>(_ object: T) throws -> Data {
        let key = try getEncryptionKey()
        let jsonData = try encoder.encode(object)
        return try AESEncryptionEngine.encrypt(data: jsonData, key: key)
    }
    
    func decrypt<T: Decodable>(_ type: T.Type, from encryptedData: Data) throws -> T {
        let key = try getEncryptionKey()
        let decryptedData = try AESEncryptionEngine.decrypt(data: encryptedData, key: key)
        return try decoder.decode(T.self, from: decryptedData)
    }
    
    func encryptString(_ string: String) throws -> Data {
        guard let data = string.data(using: .utf8) else {
            throw DataSecurityError.encodingFailed
        }
        let key = try getEncryptionKey()
        return try AESEncryptionEngine.encrypt(data: data, key: key)
    }
    
    func decryptString(from encryptedData: Data) throws -> String {
        let key = try getEncryptionKey()
        let decryptedData = try AESEncryptionEngine.decrypt(data: encryptedData, key: key)
        guard let string = String(data: decryptedData, encoding: .utf8) else {
            throw DataSecurityError.decodingFailed
        }
        return string
    }
    
    func encryptRawData(_ data: Data) throws -> Data {
        let key = try getEncryptionKey()
        return try AESEncryptionEngine.encrypt(data: data, key: key)
    }
    
    func decryptRawData(_ encryptedData: Data) throws -> Data {
        let key = try getEncryptionKey()
        return try AESEncryptionEngine.decrypt(data: encryptedData, key: key)
    }
    
    // MARK: - User Credentials
    
    func storeCredentials(_ credentials: UserCredentials) throws {
