    }
    
    // MARK: - Payment Tokens
    
    func storePaymentToken(_ token: PaymentToken) throws {
        let encryptedData = try encrypt(token)
        try keychainManager.saveGenericData(encryptedData, forAccount: paymentTokenAccount)
    }
    
    func retrievePaymentToken() throws -> PaymentToken {
        let encryptedData = try keychainManager.retrieveGenericData(forAccount: paymentTokenAccount)
        return try decrypt(PaymentToken.self, from: encryptedData)
    }
    
    func deletePaymentToken() throws {
        try keychainManager.deleteGenericData(forAccount: paymentTokenAccount)
    }
    
    // MARK: - Personal Information
    
    func storePersonalInfo(_ info: PersonalInformation) throws {
        let encryptedData = try encrypt(info)
        try keychainManager.saveGenericData(encryptedData, forAccount: personalInfoAccount)
    }
    
    func retrievePersonalInfo() throws -> PersonalInformation {
        let encryptedData = try keychainManager.retrieveGenericData(forAccount: personalInfoAccount)
        return try decrypt(PersonalInformation.self, from: encryptedData)
    }
    
    func deletePersonalInfo() throws {
        try keychainManager.deleteGenericData(forAccount: personalInfoAccount)
    }
    
    // MARK: - File-Based Encrypted Storage (for larger data)
    
    func encryptAndSaveToFile<T: Encodable>(_ object: T, filename: String) throws {
        let encryptedData = try encrypt(object)
        let fileURL = try secureStorageDirectory().appendingPathComponent(filename)
        try encryptedData.write(to: fileURL, options: [.atomic, .completeFileProtection])
    }
    
    func loadAndDecryptFromFile<T: Decodable>(_ type: T.Type, filename: String) throws -> T {
        let fileURL = try secureStorageDirectory().appendingPathComponent(filename)
        let encryptedData = try Data(contentsOf: fileURL)
        return try decrypt(T.self, from: encryptedData)
    }
    
    func deleteEncryptedFile(filename: String) throws {
        let fileURL = try secureStorageDirectory().appendingPathComponent(filename)
        if FileManager.default.fileExists(atPath: fileURL.path) {
            try FileManager.default.removeItem(at: fileURL)
        }
    }
    
    private func secureStorageDirectory() throws -> URL {
        let documentDirectory = FileManager.default.urls(for: .applicationSupportDirectory, in: .userDomainMask).first!
        let secureDir = documentDirectory.appendingPathComponent("EncryptedStorage", isDirectory: true)
        
        if !FileManager.default.fileExists(atPath: secureDir.path) {
            try FileManager.default.createDirectory(at: secureDir, withIntermediateDirectories: true, attributes: [
                .protectionKey: FileProtectionType.complete
            ])
        }
        
        return secureDir
    }
    
    // MARK: - Wipe All Data
    
    func wipeAllSecureData() throws {
        try deleteCredentials()
        try deletePaymentToken()
        try deletePersonalInfo()
        
        let secureDir = try secureStorageDirectory()
        if FileManager.default.fileExists(atPath: secureDir.path) {
            try FileManager.default.removeItem(at: secureDir)
        }
        
        keyAccessQueue.async(flags: .barrier) { [weak self] in
            self?.cachedKey = nil
        }
    }
