// MARK: - Secure Hashing Utility

final class SecureHasher {
    
    /// SHA-256 hash — use for password hashing before storing credentials
    static func sha256(_ string: String) -> String {
        guard let data = string.data(using: .utf8) else { return "" }
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes { buffer in
            _ = CC_SHA256(buffer.baseAddress, CC_LONG(data.count), &hash)
        }
        return hash.map { String(format: "%02x", $0) }.joined()
    }
    
    /// PBKDF2 key derivation — recommended for password hashing
    static func pbkdf2(password: String, salt: Data, iterations: UInt32 = 100_000, keyLength: Int = 32) throws -> Data {
        guard let passwordData = password.data(using: .utf8) else {
            throw DataSecurityError.encodingFailed
        }
        
        var derivedKey = Data(count: keyLength)
        
        let status = derivedKey.withUnsafeMutableBytes { derivedKeyBytes in
            salt.withUnsafeBytes { saltBytes in
                passwordData.withUnsafeBytes { passwordBytes in
                    CCKeyDerivationPBKDF(
                        CCPBKDFAlgorithm(kCCPBKDF2),
                        passwordBytes.baseAddress?.assumingMemoryBound(to: Int8.self),
                        passwordData.count,
                        saltBytes.baseAddress?.assumingMemoryBound(to: UInt8.self),
                        salt.count,
                        CCPseudoRandomAlgorithm(kCCPRFHmacAlgSHA256),
                        iterations,
                        derivedKeyBytes.baseAddress?.assumingMemoryBound(to: UInt8.self),
                        keyLength
                    )
                }
            }
        }
        
        guard status == kCCSuccess else {
            throw DataSecurityError.keyGenerationFailed
        }
        
        return derivedKey
    }
    
    /// Generate a cryptographically secure random salt
    static func generateSalt(length: Int = 32) throws -> Data {
        var saltData = Data(count: length)
        let result = saltData.withUnsafeMutableBytes { buffer in
            SecRandomCopyBytes(kSecRandomDefault, length, buffer.baseAddress!)
        }
        guard result == errSecSuccess else {
            throw DataSecurityError.keyGenerationFailed
        }
        return saltData
    }
}

